#!/usr/bin/env python3
"""Install or upgrade the complete Python Patch Tool v4 library.

This is a standalone library installer, not a project patch. It installs the
canonical helper, runner, template, and standard prompt into a target project.
"""

from __future__ import annotations

import argparse
import datetime as dt
from pathlib import Path
import shutil
import sys

TOOL_VERSION = "4.0.0"
INSTALLER_NAME = "install_python_patch_tool_v4"

PYTHON_PATCH_UTILS = '#!/usr/bin/env python3\n"""\nShared helper functions for one-shot Python patch scripts.\n\nVersion 4 goals:\n- Keep compatibility with older patches that use replace_exact_once(), insert_after_once(),\n  write_file_if_changed(), finish_success(), finish_failure().\n- Let ChatGPT generate much smaller patch files through run_patch(PATCH_NAME, OPS).\n- Support safer adaptive matching: exact, variant, whitespace-normalized, regex, and fuzzy\n  line-window matching.\n- Support operation-level error policy: stop, skip, or ignore.\n- Support simple if/then/else and first-success alternatives.\n- Track failed files and optionally zip them for sending back to ChatGPT.\n- Work with runner v4, which accepts standalone .py patches and .zip/.tar.gz packages.\n\nNo external dependencies. Do not put this file in patchs/; keep it in tools/.\n"""\n\nfrom __future__ import annotations\n\nPYTHON_PATCH_TOOL_VERSION = "4.0.0"\n\nPYTHON_PATCH_UTILS_RESULT_POLICY = "failed-first/no-change-only-on-0-0-v2"\n\nfrom dataclasses import dataclass, field\nfrom difflib import SequenceMatcher\nfrom pathlib import Path\nimport datetime as _dt\nimport os\nimport re\nimport shutil\nimport sys\nimport textwrap\nimport zipfile\nfrom typing import Any, Callable, Iterable, Optional\n\n\n# ---------------------------------------------------------------------------\n# Exceptions / state\n# ---------------------------------------------------------------------------\n\n\nclass PatchFailure(Exception):\n    """Patch error with a file path and human-readable diagnostic."""\n\n    def __init__(\n        self,\n        rel_path: str,\n        message: str,\n        *,\n        expected: Optional[str] = None,\n        anchor: Optional[str] = None,\n        context: Optional[str] = None,\n        op_id: Optional[str] = None,\n        strategy: Optional[str] = None,\n        candidates: Optional[list[str]] = None,\n    ) -> None:\n        self.rel_path = rel_path\n        self.message = message\n        self.expected = expected\n        self.anchor = anchor\n        self.context = context\n        self.op_id = op_id\n        self.strategy = strategy\n        self.candidates = candidates or []\n        super().__init__(f"{rel_path}: {message}")\n\n\n@dataclass\nclass PatchStats:\n    patched: int = 0\n    unchanged: int = 0\n    created: int = 0\n    backups: int = 0\n    skipped: int = 0\n    ignored: int = 0\n    failed: int = 0\n\n\n@dataclass\nclass PatchRunState:\n    project_root: Path\n    patch_name: str\n    stats: PatchStats = field(default_factory=PatchStats)\n    failures: list[PatchFailure] = field(default_factory=list)\n    failed_files: set[str] = field(default_factory=set)\n    backed_up_files: dict[str, Path] = field(default_factory=dict)\n    changed_files: set[str] = field(default_factory=set)\n\n    def record_failure(self, exc: PatchFailure) -> None:\n        self.failures.append(exc)\n        self.failed_files.add(exc.rel_path)\n        self.stats.failed += 1\n\n\n# ---------------------------------------------------------------------------\n# Project / file helpers\n# ---------------------------------------------------------------------------\n\n\ndef find_project_root(start: Optional[Path] = None) -> Path:\n    """Find the repository/project root.\n\n    Normal runner behavior runs patches with cwd=<project>. This function keeps\n    that behavior but is tolerant when a patch is invoked directly from patchs/.\n    """\n    cwd = (start or Path.cwd()).resolve()\n\n    if (cwd / "patchs").is_dir():\n        return cwd\n\n    for parent in [cwd, *cwd.parents]:\n        if parent.name == "patchs":\n            return parent.parent\n        if (parent / "patchs").is_dir():\n            return parent\n\n    raise RuntimeError("Cannot determine project root. Run patch from project root or <project>/patchs.")\n\n\ndef _safe_patch_name(patch_name: str) -> str:\n    out = re.sub(r"[^A-Za-z0-9_.-]+", "_", patch_name.strip())\n    return out or "patch"\n\n\ndef backup_path(project_root: Path, rel_path: str, patch_name: str) -> Path:\n    """Return the standard backup path for a file.\n\n    Format:\n      patchs/backup/<full-relative-path-to-file>/<stem>.<patch-name>.<original-ext>.patch.bak\n    """\n    rel = Path(rel_path)\n    suffix = rel.suffix[1:] if rel.suffix else "noext"\n    stem = rel.stem if rel.suffix else rel.name\n    backup_name = f"{stem}.{_safe_patch_name(patch_name)}.{suffix}.patch.bak"\n    return project_root / "patchs" / "backup" / rel / backup_name\n\n\ndef _non_overwriting_path(path: Path) -> Path:\n    if not path.exists():\n        return path\n    for i in range(2, 1000):\n        candidate = path.with_name(f"{path.name}.{i}")\n        if not candidate.exists():\n            return candidate\n    raise RuntimeError(f"Cannot allocate backup path near {path}")\n\n\ndef backup_file(project_root: Path, rel_path: str, patch_name: str) -> Path:\n    src = project_root / rel_path\n    if not src.exists():\n        raise PatchFailure(rel_path, "cannot back up because file does not exist")\n\n    dst = _non_overwriting_path(backup_path(project_root, rel_path, patch_name))\n    dst.parent.mkdir(parents=True, exist_ok=True)\n    shutil.copy2(src, dst)\n    return dst\n\n\ndef backup_file_once(state: PatchRunState, rel_path: str) -> Path:\n    if rel_path in state.backed_up_files:\n        return state.backed_up_files[rel_path]\n    backup = backup_file(state.project_root, rel_path, state.patch_name)\n    state.backed_up_files[rel_path] = backup\n    state.stats.backups += 1\n    return backup\n\n\ndef read_text(project_root: Path, rel_path: str) -> str:\n    path = project_root / rel_path\n    if not path.exists():\n        raise PatchFailure(rel_path, "file not found")\n    return path.read_text(encoding="utf-8")\n\n\ndef write_text(project_root: Path, rel_path: str, text: str) -> None:\n    path = project_root / rel_path\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(text, encoding="utf-8")\n\n\ndef _read_for_state(state: PatchRunState, rel_path: str) -> str:\n    return read_text(state.project_root, rel_path)\n\n\ndef _write_changed(state: PatchRunState, rel_path: str, updated: str, *, create: bool = False) -> bool:\n    path = state.project_root / rel_path\n    if path.exists():\n        old = path.read_text(encoding="utf-8")\n        if old == updated:\n            print(f"unchanged/check: {rel_path}")\n            state.stats.unchanged += 1\n            return False\n        backup = backup_file_once(state, rel_path)\n        path.write_text(updated, encoding="utf-8")\n        print(f"patched: {rel_path}")\n        print(f"backup : {backup.relative_to(state.project_root)}")\n        state.stats.patched += 1\n        state.changed_files.add(rel_path)\n        return True\n\n    if not create:\n        raise PatchFailure(rel_path, "file not found")\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(updated, encoding="utf-8")\n    print(f"created: {rel_path}")\n    state.stats.created += 1\n    state.changed_files.add(rel_path)\n    return True\n\n\n# ---------------------------------------------------------------------------\n# Context / diagnostics\n# ---------------------------------------------------------------------------\n\n\ndef _line_col_from_index(text: str, index: int) -> tuple[int, int]:\n    before = text[:index]\n    line = before.count("\\n") + 1\n    last_nl = before.rfind("\\n")\n    col = index + 1 if last_nl < 0 else index - last_nl\n    return line, col\n\n\ndef context_around_index(text: str, index: int, *, context_lines: int = 5) -> str:\n    lines = text.splitlines()\n    if not lines:\n        return "<empty file>"\n    line_no, _ = _line_col_from_index(text, max(0, min(index, len(text))))\n    line_no = max(1, min(line_no, len(lines)))\n    start = max(1, line_no - context_lines)\n    end = min(len(lines), line_no + context_lines)\n    width = len(str(end))\n    out = []\n    for n in range(start, end + 1):\n        marker = ">" if n == line_no else " "\n        out.append(f"{marker} L{n:>{width}}: {lines[n - 1]}")\n    return "\\n".join(out)\n\n\ndef context_around_pattern(text: str, pattern: str, *, context_lines: int = 5) -> Optional[str]:\n    index = text.find(pattern)\n    if index < 0:\n        return None\n    return context_around_index(text, index, context_lines=context_lines)\n\n\ndef _preview_block(block: str, *, max_lines: int = 20) -> str:\n    lines = block.splitlines()\n    shown = lines[:max_lines]\n    suffix = "" if len(lines) <= max_lines else f"\\n... ({len(lines) - max_lines} more lines)"\n    return "\\n".join(shown) + suffix\n\n\ndef print_patch_error(exc: PatchFailure) -> None:\n    RED = "\\033[91m"\n    BOLD = "\\033[1m"\n    RESET = "\\033[0m"\n    print(f"{RED}{BOLD}ERROR: {exc.message}{RESET}")\n    print(f"File : {exc.rel_path}")\n    if exc.op_id:\n        print(f"Op   : {exc.op_id}")\n    if exc.strategy:\n        print(f"Mode : {exc.strategy}")\n    if exc.anchor:\n        print(f"Anchor: {exc.anchor}")\n    if exc.expected:\n        print("Expected block preview:")\n        print(_preview_block(exc.expected))\n    if exc.context:\n        print("Nearby context:")\n        print(exc.context)\n    if exc.candidates:\n        print("Candidate contexts:")\n        for item in exc.candidates[:5]:\n            print("---")\n            print(item)\n\n\ndef _candidate_contexts(text: str, indexes: Iterable[int], *, context_lines: int = 4, limit: int = 5) -> list[str]:\n    out = []\n    for i, index in enumerate(indexes):\n        if i >= limit:\n            break\n        out.append(context_around_index(text, index, context_lines=context_lines))\n    return out\n\n\n# ---------------------------------------------------------------------------\n# Matching helpers\n# ---------------------------------------------------------------------------\n\n\n@dataclass\nclass MatchSpan:\n    start: int\n    end: int\n    strategy: str\n    score: float = 1.0\n\n\ndef _normalize_newlines(text: str) -> str:\n    return text.replace("\\r\\n", "\\n").replace("\\r", "\\n")\n\n\ndef _normalize_ws_with_map(text: str) -> tuple[str, list[int]]:\n    """Collapse whitespace to single spaces while keeping map to original indexes."""\n    out: list[str] = []\n    mapping: list[int] = []\n    in_ws = False\n    for idx, ch in enumerate(text):\n        if ch.isspace():\n            if not in_ws:\n                out.append(" ")\n                mapping.append(idx)\n                in_ws = True\n        else:\n            out.append(ch)\n            mapping.append(idx)\n            in_ws = False\n    return "".join(out), mapping\n\n\ndef _find_exact_spans(text: str, needle: str) -> list[MatchSpan]:\n    spans = []\n    start = 0\n    while True:\n        index = text.find(needle, start)\n        if index < 0:\n            break\n        spans.append(MatchSpan(index, index + len(needle), "exact"))\n        start = index + max(1, len(needle))\n    return spans\n\n\ndef _find_regex_spans(text: str, pattern: str, *, flags: int = 0) -> list[MatchSpan]:\n    return [MatchSpan(m.start(), m.end(), "regex") for m in re.finditer(pattern, text, flags)]\n\n\ndef _find_normalized_ws_spans(text: str, needle: str) -> list[MatchSpan]:\n    norm_text, text_map = _normalize_ws_with_map(text)\n    norm_needle, _ = _normalize_ws_with_map(needle)\n    if not norm_needle:\n        return []\n\n    spans = []\n    start = 0\n    while True:\n        index = norm_text.find(norm_needle, start)\n        if index < 0:\n            break\n        original_start = text_map[index]\n        norm_end = index + len(norm_needle) - 1\n        original_end = text_map[min(norm_end, len(text_map) - 1)] + 1\n        # Expand over trailing whitespace that belonged to the same original block cautiously.\n        spans.append(MatchSpan(original_start, original_end, "normalized_ws"))\n        start = index + max(1, len(norm_needle))\n    return spans\n\n\ndef _line_offsets(text: str) -> list[int]:\n    offsets = [0]\n    for m in re.finditer("\\n", text):\n        offsets.append(m.end())\n    return offsets\n\n\ndef _line_span_to_char_span(text: str, offsets: list[int], start_line: int, end_line_exclusive: int) -> tuple[int, int]:\n    start = offsets[start_line]\n    if end_line_exclusive >= len(offsets):\n        end = len(text)\n    else:\n        end = offsets[end_line_exclusive]\n    return start, end\n\n\ndef _find_fuzzy_line_spans(\n    text: str,\n    needle: str,\n    *,\n    min_ratio: float = 0.88,\n    context_hint: Optional[str] = None,\n    search_radius_lines: int = 80,\n    max_candidates: int = 5,\n) -> list[MatchSpan]:\n    """Find approximate line-window matches.\n\n    This intentionally works on line windows instead of arbitrary character windows to\n    avoid replacing a half expression. It is conservative: only a clearly best match\n    should be accepted by callers.\n    """\n    text_lf = _normalize_newlines(text)\n    needle_lf = _normalize_newlines(needle).strip("\\n")\n    if not needle_lf.strip():\n        return []\n\n    lines = text_lf.splitlines(keepends=True)\n    needle_lines = needle_lf.splitlines(keepends=True)\n    n = max(1, len(needle_lines))\n    offsets = _line_offsets(text_lf)\n\n    search_line_start = 0\n    search_line_end = len(lines)\n    if context_hint:\n        hint_index = text_lf.find(context_hint)\n        if hint_index >= 0:\n            hint_line, _ = _line_col_from_index(text_lf, hint_index)\n            center = hint_line - 1\n            search_line_start = max(0, center - search_radius_lines)\n            search_line_end = min(len(lines), center + search_radius_lines)\n\n    window_sizes = sorted(set([n, max(1, n - 2), max(1, n - 1), n + 1, n + 2]))\n    target_norm = " ".join(needle_lf.split())\n    candidates: list[MatchSpan] = []\n\n    for size in window_sizes:\n        if size <= 0:\n            continue\n        last = max(search_line_start, search_line_end - size + 1)\n        for start_line in range(search_line_start, last):\n            end_line = min(len(lines), start_line + size)\n            window = "".join(lines[start_line:end_line])\n            window_norm = " ".join(window.split())\n            if not window_norm:\n                continue\n            ratio = SequenceMatcher(None, target_norm, window_norm).ratio()\n            if ratio >= min_ratio:\n                start, end = _line_span_to_char_span(text_lf, offsets, start_line, end_line)\n                candidates.append(MatchSpan(start, end, "fuzzy", ratio))\n\n    candidates.sort(key=lambda c: c.score, reverse=True)\n    return candidates[:max_candidates]\n\n\ndef _anchor_limited_text(text: str, anchor: Optional[str], *, radius: Optional[int]) -> tuple[str, int]:\n    if not anchor or not radius:\n        return text, 0\n    index = text.find(anchor)\n    if index < 0:\n        return text, 0\n    start = max(0, index - radius)\n    end = min(len(text), index + len(anchor) + radius)\n    return text[start:end], start\n\n\ndef _find_unique_span(\n    text: str,\n    needle: str,\n    *,\n    rel_path: str,\n    anchor: Optional[str] = None,\n    op_id: Optional[str] = None,\n    mode: str = "auto",\n    variants: Optional[list[str]] = None,\n    regex_flags: int = 0,\n    context_lines: int = 6,\n    fuzzy_min: float = 0.88,\n    fuzzy_unique_gap: float = 0.04,\n    anchor_radius: Optional[int] = None,\n) -> MatchSpan:\n    if not needle and mode != "regex":\n        raise PatchFailure(rel_path, "empty search block is not allowed", op_id=op_id, anchor=anchor)\n\n    search_needles = [needle] + list(variants or [])\n    text_area, base = _anchor_limited_text(text, anchor, radius=anchor_radius)\n\n    all_spans: list[MatchSpan] = []\n\n    def add_spans(spans: list[MatchSpan]) -> None:\n        for span in spans:\n            all_spans.append(MatchSpan(span.start + base, span.end + base, span.strategy, span.score))\n\n    modes = [mode]\n    if mode == "auto":\n        modes = ["exact", "variants", "normalized_ws", "fuzzy"]\n\n    for m in modes:\n        if m == "exact":\n            add_spans(_find_exact_spans(text_area, needle))\n        elif m == "variants":\n            for variant in search_needles:\n                spans = _find_exact_spans(text_area, variant)\n                for span in spans:\n                    span.strategy = "variant" if variant != needle else "exact"\n                add_spans(spans)\n        elif m in {"normalized_ws", "whitespace", "ws"}:\n            for variant in search_needles:\n                add_spans(_find_normalized_ws_spans(text_area, variant))\n        elif m == "regex":\n            add_spans(_find_regex_spans(text_area, needle, flags=regex_flags))\n        elif m == "fuzzy":\n            add_spans(_find_fuzzy_line_spans(text_area, needle, min_ratio=fuzzy_min, context_hint=anchor))\n        elif m == "auto":\n            pass\n        else:\n            raise PatchFailure(rel_path, f"unknown search mode: {mode}", op_id=op_id, anchor=anchor)\n\n        # For auto mode, return as soon as a conservative unique match is found.\n        if mode == "auto" and all_spans:\n            break\n\n    if not all_spans:\n        context = None\n        if anchor:\n            context = context_around_pattern(text, anchor, context_lines=context_lines)\n        if context is None and needle:\n            first_line = needle.strip().splitlines()[0] if needle.strip() else needle[:80]\n            if first_line:\n                context = context_around_pattern(text, first_line, context_lines=context_lines)\n        raise PatchFailure(\n            rel_path,\n            "expected block not found",\n            expected=needle,\n            anchor=anchor,\n            context=context,\n            op_id=op_id,\n            strategy=mode,\n        )\n\n    # De-duplicate identical spans.\n    dedup: dict[tuple[int, int], MatchSpan] = {}\n    for span in all_spans:\n        key = (span.start, span.end)\n        if key not in dedup or span.score > dedup[key].score:\n            dedup[key] = span\n    spans = sorted(dedup.values(), key=lambda s: s.score, reverse=True)\n\n    if len(spans) == 1:\n        return spans[0]\n\n    if spans[0].strategy == "fuzzy":\n        if spans[0].score >= fuzzy_min and (spans[0].score - spans[1].score) >= fuzzy_unique_gap:\n            return spans[0]\n\n    indexes = [s.start for s in spans]\n    raise PatchFailure(\n        rel_path,\n        f"expected block found {len(spans)} times; patch is ambiguous",\n        expected=needle,\n        anchor=anchor,\n        context=context_around_index(text, spans[0].start, context_lines=context_lines),\n        op_id=op_id,\n        strategy=mode,\n        candidates=_candidate_contexts(text, indexes, context_lines=context_lines),\n    )\n\n\ndef _already_patched(text: str, new: Optional[str], already: Any = None) -> bool:\n    checks: list[str] = []\n    if isinstance(already, str):\n        checks = [already]\n    elif isinstance(already, list):\n        checks = [str(x) for x in already]\n    elif new:\n        checks = [new]\n    return any(check and check in text for check in checks)\n\n\n# ---------------------------------------------------------------------------\n# Operation implementations\n# ---------------------------------------------------------------------------\n\n\ndef op_replace(state: PatchRunState, op: dict[str, Any]) -> bool:\n    rel_path = op["file"]\n    old = op.get("old", "")\n    new = op.get("new", "")\n    anchor = op.get("anchor")\n    op_id = op.get("id") or op.get("desc")\n    mode = op.get("mode", "auto")\n    context_lines = int(op.get("context_lines", 6))\n\n    text = _read_for_state(state, rel_path)\n    if _already_patched(text, new, op.get("already")):\n        print(f"already patched/check: {rel_path}")\n        state.stats.unchanged += 1\n        return False\n\n    span = _find_unique_span(\n        text,\n        old,\n        rel_path=rel_path,\n        anchor=anchor,\n        op_id=op_id,\n        mode=mode,\n        variants=op.get("old_variants"),\n        regex_flags=int(op.get("regex_flags", 0)),\n        context_lines=context_lines,\n        fuzzy_min=float(op.get("fuzzy_min", 0.88)),\n        fuzzy_unique_gap=float(op.get("fuzzy_unique_gap", 0.04)),\n        anchor_radius=op.get("anchor_radius"),\n    )\n    updated = text[: span.start] + new + text[span.end :]\n    changed = _write_changed(state, rel_path, updated)\n    if span.strategy != "exact":\n        print(f"match  : {span.strategy} score={span.score:.3f} file={rel_path}")\n    return changed\n\n\ndef op_replace_any(state: PatchRunState, op: dict[str, Any]) -> bool:\n    """Try several old->new alternatives and apply the first unambiguous match."""\n    rel_path = op["file"]\n    replacements = op.get("replacements") or []\n    if not replacements:\n        raise PatchFailure(rel_path, "replace_any requires replacements[]", op_id=op.get("id"))\n    errors: list[PatchFailure] = []\n    for index, repl in enumerate(replacements, start=1):\n        child = dict(op)\n        child.pop("replacements", None)\n        child.update(repl)\n        child.setdefault("id", f"{op.get(\'id\') or \'replace_any\'}#{index}")\n        try:\n            return op_replace(state, child)\n        except PatchFailure as exc:\n            errors.append(exc)\n    first = errors[0]\n    raise PatchFailure(\n        rel_path,\n        f"none of {len(replacements)} replacement alternatives matched",\n        expected=first.expected,\n        anchor=op.get("anchor"),\n        context=first.context,\n        op_id=op.get("id"),\n        strategy="replace_any",\n    )\n\n\ndef op_regex_replace(state: PatchRunState, op: dict[str, Any]) -> bool:\n    rel_path = op["file"]\n    pattern = op["pattern"]\n    repl = op.get("repl", op.get("new", ""))\n    flags = int(op.get("regex_flags", re.MULTILINE))\n    expected_count = op.get("count", op.get("expected_count", 1))\n    anchor = op.get("anchor")\n    op_id = op.get("id") or op.get("desc")\n    context_lines = int(op.get("context_lines", 6))\n\n    text = _read_for_state(state, rel_path)\n    if _already_patched(text, op.get("already"), op.get("already")):\n        print(f"already patched/check: {rel_path}")\n        state.stats.unchanged += 1\n        return False\n\n    area, base = _anchor_limited_text(text, anchor, radius=op.get("anchor_radius"))\n    match_count = len(list(re.finditer(pattern, area, flags)))\n    if expected_count not in {None, "any"} and match_count != int(expected_count):\n        ctx = context_around_pattern(text, anchor, context_lines=context_lines) if anchor else None\n        candidates = _candidate_contexts(area, [m.start() for m in re.finditer(pattern, area, flags)], context_lines=context_lines)\n        raise PatchFailure(\n            rel_path,\n            f"regex replacement count mismatch: expected {expected_count}, got {match_count}",\n            expected=pattern,\n            anchor=anchor,\n            context=ctx,\n            op_id=op_id,\n            strategy="regex_replace",\n            candidates=candidates,\n        )\n    updated_area, count = re.subn(pattern, repl, area, count=0 if expected_count in {None, "any"} else int(expected_count), flags=flags)\n\n    if count == 0:\n        raise PatchFailure(\n            rel_path,\n            "regex pattern not found",\n            expected=pattern,\n            anchor=anchor,\n            context=context_around_pattern(text, anchor, context_lines=context_lines) if anchor else None,\n            op_id=op_id,\n            strategy="regex_replace",\n        )\n\n    updated = text[:base] + updated_area + text[base + len(area) :]\n    return _write_changed(state, rel_path, updated)\n\n\ndef op_insert(state: PatchRunState, op: dict[str, Any], *, before: bool = False) -> bool:\n    rel_path = op["file"]\n    anchor = op["anchor"]\n    insertion = op.get("insert", op.get("insertion", ""))\n    op_id = op.get("id") or op.get("desc")\n    mode = op.get("mode", "auto")\n    context_lines = int(op.get("context_lines", 6))\n\n    text = _read_for_state(state, rel_path)\n    if _already_patched(text, insertion, op.get("already")):\n        print(f"already patched/check: {rel_path}")\n        state.stats.unchanged += 1\n        return False\n\n    span = _find_unique_span(\n        text,\n        anchor,\n        rel_path=rel_path,\n        anchor=op.get("context_anchor") or anchor,\n        op_id=op_id,\n        mode=mode,\n        variants=op.get("anchor_variants"),\n        regex_flags=int(op.get("regex_flags", 0)),\n        context_lines=context_lines,\n        fuzzy_min=float(op.get("fuzzy_min", 0.88)),\n        fuzzy_unique_gap=float(op.get("fuzzy_unique_gap", 0.04)),\n        anchor_radius=op.get("anchor_radius"),\n    )\n    at = span.start if before else span.end\n    updated = text[:at] + insertion + text[at:]\n    changed = _write_changed(state, rel_path, updated)\n    if span.strategy != "exact":\n        print(f"match  : {span.strategy} score={span.score:.3f} file={rel_path}")\n    return changed\n\n\ndef op_append(state: PatchRunState, op: dict[str, Any]) -> bool:\n    rel_path = op["file"]\n    content = op.get("content", op.get("insert", ""))\n    text = _read_for_state(state, rel_path)\n    if _already_patched(text, content, op.get("already")):\n        print(f"already patched/check: {rel_path}")\n        state.stats.unchanged += 1\n        return False\n    sep = "" if text.endswith("\\n") or not text else "\\n"\n    return _write_changed(state, rel_path, text + sep + content)\n\n\ndef op_prepend(state: PatchRunState, op: dict[str, Any]) -> bool:\n    rel_path = op["file"]\n    content = op.get("content", op.get("insert", ""))\n    text = _read_for_state(state, rel_path)\n    if _already_patched(text, content, op.get("already")):\n        print(f"already patched/check: {rel_path}")\n        state.stats.unchanged += 1\n        return False\n    return _write_changed(state, rel_path, content + text)\n\n\ndef op_write(state: PatchRunState, op: dict[str, Any]) -> bool:\n    rel_path = op["file"]\n    content = op.get("content", "")\n    create = bool(op.get("create", True))\n    return _write_changed(state, rel_path, content, create=create)\n\n\ndef _condition_matches(state: PatchRunState, condition: dict[str, Any]) -> bool:\n    rel_path = condition.get("file")\n    if condition.get("path_exists") is not None:\n        p = state.project_root / str(condition["path_exists"])\n        return p.exists()\n    if not rel_path:\n        raise PatchFailure("<condition>", "condition requires file or path_exists")\n    path = state.project_root / rel_path\n    exists = path.exists()\n    if condition.get("exists") is not None:\n        return exists is bool(condition["exists"])\n    if not exists:\n        return False\n    text = path.read_text(encoding="utf-8")\n    if "contains" in condition:\n        return str(condition["contains"]) in text\n    if "not_contains" in condition:\n        return str(condition["not_contains"]) not in text\n    if "regex" in condition:\n        return re.search(str(condition["regex"]), text, int(condition.get("regex_flags", re.MULTILINE))) is not None\n    if "not_regex" in condition:\n        return re.search(str(condition["not_regex"]), text, int(condition.get("regex_flags", re.MULTILINE))) is None\n    raise PatchFailure(rel_path, "unknown condition")\n\n\ndef op_if(state: PatchRunState, op: dict[str, Any]) -> bool:\n    condition = op.get("condition") or {k: op[k] for k in ("file", "contains", "not_contains", "regex", "not_regex", "exists", "path_exists") if k in op}\n    branch = op.get("then", []) if _condition_matches(state, condition) else op.get("else", [])\n    if not branch:\n        print(f"condition/no-op: {op.get(\'id\') or condition}")\n        state.stats.unchanged += 1\n        return False\n    before = (state.stats.patched, state.stats.created, state.stats.unchanged)\n    _apply_ops(state, branch, inherited_on_error=op.get("on_error", "stop"))\n    after = (state.stats.patched, state.stats.created, state.stats.unchanged)\n    return after != before\n\n\ndef op_first_success(state: PatchRunState, op: dict[str, Any]) -> bool:\n    """Try alternatives until one succeeds.\n\n    Alternatives should be independent. This function is best for finding local code\n    shape A vs B before any write happens. If an alternative partially writes then\n    fails, that failure is not rolled back; keep alternatives small and atomic.\n    """\n    rel_path = op.get("file", "<multi-file>")\n    alternatives = op.get("alternatives") or []\n    if not alternatives:\n        raise PatchFailure(rel_path, "first_success requires alternatives[]", op_id=op.get("id"))\n    errors: list[PatchFailure] = []\n    for index, alt in enumerate(alternatives, start=1):\n        checkpoint = (state.stats.patched, state.stats.created, state.stats.unchanged, len(state.failures))\n        try:\n            ops = alt if isinstance(alt, list) else [alt]\n            _apply_ops(state, ops, inherited_on_error="stop")\n            print(f"first_success: selected alternative #{index} ({op.get(\'id\') or rel_path})")\n            return True\n        except PatchFailure as exc:\n            # Only safe if the alternative failed before writing. If it wrote and then\n            # failed, do not continue because rollback is intentionally not implicit.\n            wrote = (state.stats.patched, state.stats.created) != checkpoint[:2]\n            errors.append(exc)\n            if wrote:\n                raise PatchFailure(\n                    rel_path,\n                    f"alternative #{index} failed after writing; refusing to try next alternative",\n                    expected=exc.expected,\n                    anchor=exc.anchor,\n                    context=exc.context,\n                    op_id=op.get("id"),\n                    strategy="first_success",\n                )\n            # Remove any failure that was recorded by nested code before retrying.\n            while len(state.failures) > checkpoint[3]:\n                state.failures.pop()\n            state.stats.failed = max(0, state.stats.failed - 1)\n    first = errors[0]\n    raise PatchFailure(\n        rel_path,\n        f"all {len(alternatives)} alternatives failed",\n        expected=first.expected,\n        anchor=first.anchor,\n        context=first.context,\n        op_id=op.get("id"),\n        strategy="first_success",\n    )\n\n\n_OPS: dict[str, Callable[[PatchRunState, dict[str, Any]], bool]] = {\n    "replace": op_replace,\n    "replace_exact": lambda s, o: op_replace(s, {**o, "mode": "exact"}),\n    "replace_ws": lambda s, o: op_replace(s, {**o, "mode": "normalized_ws"}),\n    "replace_fuzzy": lambda s, o: op_replace(s, {**o, "mode": "fuzzy"}),\n    "replace_any": op_replace_any,\n    "regex_replace": op_regex_replace,\n    "insert_after": lambda s, o: op_insert(s, o, before=False),\n    "insert_before": lambda s, o: op_insert(s, o, before=True),\n    "append": op_append,\n    "prepend": op_prepend,\n    "write": op_write,\n    "if": op_if,\n    "first_success": op_first_success,\n}\n\n\ndef _apply_one(state: PatchRunState, op: dict[str, Any], *, inherited_on_error: str) -> None:\n    kind = op.get("kind", "replace")\n    on_error = op.get("on_error", inherited_on_error)\n    if kind not in _OPS:\n        raise PatchFailure(op.get("file", "<operation>"), f"unknown operation kind: {kind}", op_id=op.get("id"))\n\n    try:\n        _OPS[kind](state, op)\n    except PatchFailure as exc:\n        if not exc.op_id and op.get("id"):\n            exc.op_id = str(op["id"])\n        if on_error == "skip":\n            state.record_failure(exc)\n            state.stats.skipped += 1\n            print_patch_error(exc)\n            YELLOW = "\\033[93m"\n            RESET = "\\033[0m"\n            print(f"{YELLOW}SKIP : continuing after failed operation ({op.get(\'id\') or kind}){RESET}")\n            return\n        if on_error == "ignore":\n            state.stats.ignored += 1\n            YELLOW = "\\033[93m"\n            RESET = "\\033[0m"\n            print(f"{YELLOW}IGNORE: {exc.rel_path}: {exc.message}{RESET}")\n            return\n        raise exc\n\n\ndef _apply_ops(state: PatchRunState, ops: Iterable[dict[str, Any]], *, inherited_on_error: str = "stop") -> None:\n    for op in ops:\n        _apply_one(state, op, inherited_on_error=inherited_on_error)\n\n\n# ---------------------------------------------------------------------------\n# Public runner API\n# ---------------------------------------------------------------------------\n\n\ndef apply_ops(\n    project_root: Path,\n    patch_name: str,\n    ops: Iterable[dict[str, Any]],\n    *,\n    default_on_error: str = "stop",\n) -> PatchRunState:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    try:\n        _apply_ops(state, ops, inherited_on_error=default_on_error)\n    except PatchFailure as exc:\n        state.record_failure(exc)\n        print_patch_error(exc)\n    return state\n\n\ndef print_summary(state: PatchRunState) -> None:\n    RED = "\\033[91m"\n    YELLOW = "\\033[93m"\n    BOLD = "\\033[1m"\n    RESET = "\\033[0m"\n    s = state.stats\n\n    # A failure always retains the complete summary. The no-change banner is\n    # valid only when the run succeeded and both patched and created are zero.\n    if s.failed == 0 and s.patched == 0 and s.created == 0:\n        print()\n        print(f"{YELLOW}{BOLD}============================================================{RESET}")\n        print(f"{YELLOW}{BOLD}PATCH KHÔNG THAY ĐỔI CODE{RESET}")\n        print(f"{YELLOW}{BOLD}============================================================{RESET}")\n        print()\n        return\n\n    print("Patch summary:")\n    print(f"  patched : {s.patched}")\n    print(f"  created : {s.created}")\n    print(f"  unchanged/check: {s.unchanged}")\n    print(f"  backups : {s.backups}")\n    if s.failed > 0:\n        print(f"  failed  : {RED}{s.failed}{RESET}")\n    else:\n        print(f"  failed  : {s.failed}")\n    if s.skipped:\n        print(f"  skipped : {s.skipped}")\n    if s.ignored:\n        print(f"  ignored : {s.ignored}")\n    if state.failed_files:\n        print(f"{RED}Failed files:{RESET}")\n        for rel_path in sorted(state.failed_files):\n            print(f"  - {rel_path}")\n\n\ndef zip_failed_files(state: PatchRunState) -> Optional[Path]:\n    if not state.failed_files:\n        return None\n    ts = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")\n    out_dir = state.project_root / "patchs" / "failed_patch_files"\n    out_dir.mkdir(parents=True, exist_ok=True)\n    zip_path = out_dir / f"{_safe_patch_name(state.patch_name)}_failed_{ts}.zip"\n    \n    # Map failed rel_paths to their respective failures to look up expected/old content if missing\n    failure_map = {exc.rel_path: exc for exc in state.failures}\n    \n    with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as zf:\n        # 1. Zip the running patch script itself if found\n        patch_file_path = None\n        if sys.argv and sys.argv[0]:\n            argv_path = Path(sys.argv[0]).resolve()\n            if argv_path.exists() and argv_path.is_file() and argv_path.suffix == ".py":\n                patch_file_path = argv_path\n        if not patch_file_path:\n            candidate = state.project_root / "patchs" / f"patch_{state.patch_name}.py"\n            if candidate.exists():\n                patch_file_path = candidate\n                \n        if patch_file_path:\n            try:\n                rel_patch = patch_file_path.relative_to(state.project_root)\n            except ValueError:\n                rel_patch = Path("patchs") / patch_file_path.name\n            zf.write(patch_file_path, arcname=str(rel_patch))\n\n        # 2. Zip all failed files (or write expected content if they don\'t exist)\n        for rel_path in sorted(state.failed_files):\n            path = state.project_root / rel_path\n            if path.exists() and path.is_file():\n                zf.write(path, arcname=rel_path)\n            else:\n                exc = failure_map.get(rel_path)\n                content = ""\n                if exc and exc.expected:\n                    content = exc.expected\n                else:\n                    content = f"// ERROR: File {rel_path} was not found on disk during patch execution.\\n"\n                zf.writestr(rel_path, content)\n                \n    print(f"failed-files zip: {zip_path.resolve()}")\n    return zip_path\n\n\ndef maybe_prompt_zip_failed_files(\n    state: PatchRunState,\n    *,\n    force: Optional[bool] = None,\n    delete_generated_zip: Optional[bool] = None,\n) -> Optional[Path]:\n    if not state.failed_files:\n        return None\n    if force is False:\n        print("Zip failed files: skipped by patch setting.")\n        return None\n\n    zip_path = None\n    if force is True:\n        zip_path = zip_failed_files(state)\n    else:\n        if not sys.stdin.isatty():\n            print("Zip failed files: skipped because stdin is not interactive.")\n            print("Use --zip-failed to create it without a prompt.")\n            return None\n        answer = input("Có zip toàn bộ file patch lỗi để gửi lên ChatGPT không? [Y/n]: ").strip().lower()\n        if answer in {"", "y", "yes", "c", "co", "có"}:\n            zip_path = zip_failed_files(state)\n        else:\n            print("Zip failed files: no")\n\n    if not zip_path or not zip_path.exists():\n        return zip_path\n\n    try:\n        rel_zip = zip_path.relative_to(state.project_root)\n    except Exception:\n        rel_zip = zip_path\n\n    if delete_generated_zip is True:\n        zip_path.unlink()\n        print(f"Deleted: {rel_zip}")\n        return zip_path\n    if delete_generated_zip is False:\n        print(f"Kept: {rel_zip}")\n        return zip_path\n    if not sys.stdin.isatty():\n        print(f"Kept: {rel_zip}")\n        return zip_path\n\n    try:\n        answer = input(f"Delete this generated zip file: {rel_zip}? [Y/n]: ").strip().lower()\n        if answer in {"", "y", "yes", "c", "co", "có"}:\n            zip_path.unlink()\n            print(f"Deleted: {rel_zip}")\n        else:\n            print(f"Kept: {rel_zip}")\n    except KeyboardInterrupt:\n        print(f"\\nKept: {rel_zip}")\n    except Exception as exc:\n        print(f"Error deleting zip file: {exc}")\n\n    return zip_path\n\n\ndef _print_patch_cli_help(patch_name: str) -> None:\n    print(f"Usage: {Path(sys.argv[0]).name} [PATCH OPTIONS]")\n    print()\n    print(f"Patch: {patch_name}")\n    print()\n    print("Options handled by tools/python_patch_utils.py:")\n    print("  -h, --help                 Show this help and do not apply the patch")\n    print("      --zip-failed           Create failed-files ZIP without asking")\n    print("      --no-zip-failed        Never create failed-files ZIP")\n    print("      --delete-failed-zip    Delete generated failed-files ZIP")\n    print("      --keep-failed-zip      Keep generated failed-files ZIP")\n    print()\n    print("Unknown options are left available for patch-specific code.")\n\n\ndef _read_patch_cli_options(patch_name: str) -> tuple[bool, Optional[bool], Optional[bool]]:\n    help_requested = False\n    zip_failed: Optional[bool] = None\n    delete_failed_zip: Optional[bool] = None\n\n    for arg in sys.argv[1:]:\n        if arg in {"-h", "--help"}:\n            help_requested = True\n        elif arg == "--zip-failed":\n            zip_failed = True\n        elif arg == "--no-zip-failed":\n            zip_failed = False\n        elif arg == "--delete-failed-zip":\n            delete_failed_zip = True\n        elif arg == "--keep-failed-zip":\n            delete_failed_zip = False\n\n    if help_requested:\n        _print_patch_cli_help(patch_name)\n    return help_requested, zip_failed, delete_failed_zip\n\n\ndef run_patch(\n    patch_name: str,\n    ops: Iterable[dict[str, Any]],\n    *,\n    default_on_error: str = "stop",\n    prompt_zip_on_error: Optional[bool] = None,\n    delete_failed_zip: Optional[bool] = None,\n) -> int:\n    help_requested, cli_zip_failed, cli_delete_failed_zip = _read_patch_cli_options(patch_name)\n    if help_requested:\n        return 0\n\n    if cli_zip_failed is not None:\n        prompt_zip_on_error = cli_zip_failed\n    if cli_delete_failed_zip is not None:\n        delete_failed_zip = cli_delete_failed_zip\n\n    root = find_project_root()\n    state = apply_ops(root, patch_name, ops, default_on_error=default_on_error)\n    print_summary(state)\n    maybe_prompt_zip_failed_files(\n        state,\n        force=prompt_zip_on_error,\n        delete_generated_zip=delete_failed_zip,\n    )\n    if state.failures:\n        RED = "\\033[91m"\n        BOLD = "\\033[1m"\n        RESET = "\\033[0m"\n        print(f"{RED}{BOLD}Patch completed with errors.{RESET}")\n        return 1\n    print("Patch completed successfully.")\n    return 0\n\n\n# ---------------------------------------------------------------------------\n# Backward-compatible legacy functions\n# ---------------------------------------------------------------------------\n\n\ndef replace_exact_once(\n    project_root: Path,\n    rel_path: str,\n    old: str,\n    new: str,\n    patch_name: str,\n    *,\n    anchor: Optional[str] = None,\n    context_lines: int = 6,\n) -> bool:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    return op_replace(\n        state,\n        {\n            "kind": "replace_exact",\n            "file": rel_path,\n            "old": old,\n            "new": new,\n            "anchor": anchor,\n            "context_lines": context_lines,\n        },\n    )\n\n\ndef replace_ws_once(\n    project_root: Path,\n    rel_path: str,\n    old: str,\n    new: str,\n    patch_name: str,\n    *,\n    anchor: Optional[str] = None,\n    context_lines: int = 6,\n) -> bool:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    return op_replace(\n        state,\n        {\n            "kind": "replace_ws",\n            "file": rel_path,\n            "old": old,\n            "new": new,\n            "anchor": anchor,\n            "context_lines": context_lines,\n        },\n    )\n\n\ndef replace_fuzzy_once(\n    project_root: Path,\n    rel_path: str,\n    old: str,\n    new: str,\n    patch_name: str,\n    *,\n    anchor: Optional[str] = None,\n    fuzzy_min: float = 0.88,\n    context_lines: int = 6,\n) -> bool:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    return op_replace(\n        state,\n        {\n            "kind": "replace_fuzzy",\n            "file": rel_path,\n            "old": old,\n            "new": new,\n            "anchor": anchor,\n            "fuzzy_min": fuzzy_min,\n            "context_lines": context_lines,\n        },\n    )\n\n\ndef insert_after_once(\n    project_root: Path,\n    rel_path: str,\n    anchor: str,\n    insertion: str,\n    patch_name: str,\n    *,\n    context_lines: int = 6,\n) -> bool:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    return op_insert(\n        state,\n        {\n            "kind": "insert_after",\n            "file": rel_path,\n            "anchor": anchor,\n            "insert": insertion,\n            "context_lines": context_lines,\n        },\n        before=False,\n    )\n\n\ndef insert_before_once(\n    project_root: Path,\n    rel_path: str,\n    anchor: str,\n    insertion: str,\n    patch_name: str,\n    *,\n    context_lines: int = 6,\n) -> bool:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    return op_insert(\n        state,\n        {\n            "kind": "insert_before",\n            "file": rel_path,\n            "anchor": anchor,\n            "insert": insertion,\n            "context_lines": context_lines,\n        },\n        before=True,\n    )\n\n\ndef write_file_if_changed(project_root: Path, rel_path: str, content: str, patch_name: str) -> bool:\n    state = PatchRunState(project_root=project_root, patch_name=patch_name)\n    return op_write(state, {"kind": "write", "file": rel_path, "content": content, "create": True})\n\n\ndef finish_success() -> None:\n    print("Patch completed successfully.")\n\n\ndef finish_failure(exc: Exception) -> int:\n    if isinstance(exc, PatchFailure):\n        print_patch_error(exc)\n    else:\n        RED = "\\033[91m"\n        BOLD = "\\033[1m"\n        RESET = "\\033[0m"\n        print(f"{RED}{BOLD}ERROR: unexpected patch failure: {exc}{RESET}")\n    return 1\n'
RUN_PYTHON_PATCHES = '#!/usr/bin/env bash\nset -u\nset -o pipefail\n\nTOOL_VERSION="4.0.0"\n\n# Python patch runner mini-AI v4.\n#\n# Expected location:\n#   <project>/tools/run_python_patches.sh\n#\n# Supported patch inputs in <project>/patchs:\n#   - standalone Python patch: *.py\n#   - ZIP package           : *.zip\n#   - tar.gz package        : *.tar.gz or *.tgz\n#\n# Archive workflow:\n#   - safely extract to patchs/.patch_runner_tmp/\n#   - execute patch_*.py recursively in deterministic order\n#   - if no patch_*.py exists, execute every *.py recursively\n#   - remove the extracted temporary files\n#   - optionally move only the original archive to patchs/patched/\n#\n# Standalone Python patches are also optionally moved to patchs/patched/\n# after execution. Existing files in patched/ are never overwritten.\n\nSCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"\nPROJECT_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"\nPATCH_DIR="${PROJECT_ROOT}/patchs"\nPATCHED_DIR="${PATCH_DIR}/patched"\nTEMP_ROOT="${PATCH_DIR}/.patch_runner_tmp"\nTOOLS_DIR="${PROJECT_ROOT}/tools"\nPATCH_HELPER="${TOOLS_DIR}/python_patch_utils.py"\nCURRENT_TEMP_DIR=""\nRUN_MODE="interactive"\nPATCH_SELECTOR=""\nMOVE_MODE="ask"\nASSUME_YES=0\nPATCH_CLI_ARGS=()\n\nusage() {\n    cat <<\'EOF\'\nUsage: ./tools/run_python_patches.sh [OPTIONS] [PATCH]\n\nRun Python patch scripts or compressed patch packages from patchs/.\nWithout arguments, the runner keeps the interactive selection workflow.\n\nSelection:\n  -a, --all                    Run all patch files/packages\n  -p, --patch PATCH            Run one patch by number, basename, relative path,\n                               or absolute path\n  -l, --list                   List available patches and exit\n      PATCH                    Positional alias for --patch PATCH\n\nConfirmation control:\n  -y, --yes                    Fully non-interactive defaults: run all when no\n                               patch is selected, move successful inputs, and\n                               create/keep a failed-files ZIP on failure\n      --move                   Move successful input to patchs/patched/\n      --keep, --no-move        Keep successful input in patchs/\n\nFailed-file ZIP options passed to helper-based Python patches:\n      --zip-failed             Create failed-files ZIP without asking\n      --no-zip-failed          Never create failed-files ZIP\n      --delete-failed-zip      Delete generated failed-files ZIP\n      --keep-failed-zip        Keep generated failed-files ZIP\n\nOther:\n  -h, --help                   Show this help and exit\n\nBehavior:\n  Any failed patch stops the runner immediately. Failed inputs are kept in\n  patchs/ and are never moved to patchs/patched/.\n\nExamples:\n  ./tools/run_python_patches.sh --all --move\n  ./tools/run_python_patches.sh -y\n  ./tools/run_python_patches.sh --patch 2 --keep\n  ./tools/run_python_patches.sh patch_feature.zip --move\n  ./tools/run_python_patches.sh --all --zip-failed --keep-failed-zip --move\nEOF\n}\n\nset_patch_cli_flag() {\n    local positive="$1"\n    local negative="$2"\n    local requested="$3"\n    local existing\n\n    for existing in "${PATCH_CLI_ARGS[@]}"; do\n        if [ "${existing}" = "${positive}" ] || [ "${existing}" = "${negative}" ]; then\n            echo "ERROR: Conflicting patch option: ${existing} and ${requested}" >&2\n            exit 2\n        fi\n    done\n    PATCH_CLI_ARGS+=("${requested}")\n}\n\nwhile [ "$#" -gt 0 ]; do\n    case "$1" in\n        -h|--help)\n            usage\n            exit 0\n            ;;\n        -a|--all)\n            if [ "${RUN_MODE}" = "one" ]; then\n                echo "ERROR: --all cannot be combined with --patch." >&2\n                exit 2\n            fi\n            RUN_MODE="all"\n            ;;\n        -p|--patch)\n            if [ "$#" -lt 2 ]; then\n                echo "ERROR: $1 requires a patch selector." >&2\n                exit 2\n            fi\n            if [ "${RUN_MODE}" = "all" ] || [ "${RUN_MODE}" = "one" ]; then\n                echo "ERROR: Only one patch selection mode may be used." >&2\n                exit 2\n            fi\n            RUN_MODE="one"\n            PATCH_SELECTOR="$2"\n            shift\n            ;;\n        --patch=*)\n            if [ "${RUN_MODE}" = "all" ] || [ "${RUN_MODE}" = "one" ]; then\n                echo "ERROR: Only one patch selection mode may be used." >&2\n                exit 2\n            fi\n            RUN_MODE="one"\n            PATCH_SELECTOR="${1#*=}"\n            ;;\n        -l|--list)\n            if [ "${RUN_MODE}" != "interactive" ]; then\n                echo "ERROR: --list cannot be combined with a run selection." >&2\n                exit 2\n            fi\n            RUN_MODE="list"\n            ;;\n        -y|--yes)\n            ASSUME_YES=1\n            ;;\n        --move)\n            if [ "${MOVE_MODE}" = "keep" ]; then\n                echo "ERROR: --move conflicts with --keep/--no-move." >&2\n                exit 2\n            fi\n            MOVE_MODE="move"\n            ;;\n        --keep|--no-move)\n            if [ "${MOVE_MODE}" = "move" ]; then\n                echo "ERROR: --keep/--no-move conflicts with --move." >&2\n                exit 2\n            fi\n            MOVE_MODE="keep"\n            ;;\n        --zip-failed)\n            set_patch_cli_flag "--zip-failed" "--no-zip-failed" "$1"\n            ;;\n        --no-zip-failed)\n            set_patch_cli_flag "--zip-failed" "--no-zip-failed" "$1"\n            ;;\n        --delete-failed-zip)\n            set_patch_cli_flag "--delete-failed-zip" "--keep-failed-zip" "$1"\n            ;;\n        --keep-failed-zip)\n            set_patch_cli_flag "--delete-failed-zip" "--keep-failed-zip" "$1"\n            ;;\n        --)\n            shift\n            if [ "$#" -gt 1 ]; then\n                echo "ERROR: Only one positional patch selector is supported." >&2\n                exit 2\n            fi\n            if [ "$#" -eq 1 ]; then\n                if [ "${RUN_MODE}" != "interactive" ]; then\n                    echo "ERROR: Positional PATCH conflicts with another selection mode." >&2\n                    exit 2\n                fi\n                RUN_MODE="one"\n                PATCH_SELECTOR="$1"\n            fi\n            break\n            ;;\n        -*)\n            echo "ERROR: Unknown option: $1" >&2\n            echo "Use --help for usage." >&2\n            exit 2\n            ;;\n        *)\n            if [ "${RUN_MODE}" != "interactive" ]; then\n                echo "ERROR: Positional PATCH conflicts with another selection mode." >&2\n                exit 2\n            fi\n            RUN_MODE="one"\n            PATCH_SELECTOR="$1"\n            ;;\n    esac\n    shift\ndone\n\nif [ "${ASSUME_YES}" -eq 1 ]; then\n    if [ "${RUN_MODE}" = "interactive" ]; then\n        RUN_MODE="all"\n    fi\n    if [ "${MOVE_MODE}" = "ask" ]; then\n        MOVE_MODE="move"\n    fi\n\n    has_zip_choice=0\n    has_delete_choice=0\n    for patch_arg in "${PATCH_CLI_ARGS[@]}"; do\n        case "${patch_arg}" in\n            --zip-failed|--no-zip-failed) has_zip_choice=1 ;;\n            --delete-failed-zip|--keep-failed-zip) has_delete_choice=1 ;;\n        esac\n    done\n    if [ "${has_zip_choice}" -eq 0 ]; then\n        PATCH_CLI_ARGS+=("--zip-failed")\n    fi\n    if [ "${has_delete_choice}" -eq 0 ]; then\n        PATCH_CLI_ARGS+=("--keep-failed-zip")\n    fi\nfi\n\nif command -v python3 >/dev/null 2>&1; then\n    PYTHON_BIN="python3"\nelif command -v python >/dev/null 2>&1; then\n    PYTHON_BIN="python"\nelse\n    echo "ERROR: Cannot find python3 or python in PATH."\n    exit 1\nfi\n\nif [ ! -d "${PATCH_DIR}" ]; then\n    echo "ERROR: Patch directory not found: ${PATCH_DIR}"\n    echo "Create it first, for example:"\n    echo "  mkdir -p patchs"\n    exit 1\nfi\n\nif [ ! -d "${TOOLS_DIR}" ]; then\n    echo "ERROR: Tools directory not found: ${TOOLS_DIR}"\n    exit 1\nfi\n\nmkdir -p -- "${PATCHED_DIR}" "${TEMP_ROOT}"\n\ncleanup_current_temp() {\n    if [ -n "${CURRENT_TEMP_DIR}" ] && [ -d "${CURRENT_TEMP_DIR}" ]; then\n        case "${CURRENT_TEMP_DIR}" in\n            "${TEMP_ROOT}"/*)\n                rm -rf -- "${CURRENT_TEMP_DIR}"\n                ;;\n            *)\n                echo "WARNING: Refusing to remove unexpected temp path: ${CURRENT_TEMP_DIR}" >&2\n                ;;\n        esac\n    fi\n    CURRENT_TEMP_DIR=""\n}\n\ntrap cleanup_current_temp EXIT\ntrap \'cleanup_current_temp; exit 130\' INT TERM HUP\n\nmapfile -d \'\' -t PATCH_ITEMS < <(\n    find "${PATCH_DIR}" -maxdepth 1 -type f \\\n        \\( -iname "*.py" -o -iname "*.zip" -o -iname "*.tar.gz" -o -iname "*.tgz" \\) \\\n        -print0 | sort -z\n)\n\nif [ "${#PATCH_ITEMS[@]}" -eq 0 ]; then\n    echo "No patch files found in: ${PATCH_DIR}"\n    echo "Supported formats: .py, .zip, .tar.gz, .tgz"\n    exit 0\nfi\n\nask_yes_no() {\n    local prompt="$1"\n    local answer\n\n    if [ "${ASSUME_YES}" -eq 1 ]; then\n        echo "${prompt} [Y/n]: Y (--yes)"\n        return 0\n    fi\n\n    while true; do\n        read -r -p "${prompt} [Y/n]: " answer\n        case "${answer}" in\n            y|Y|yes|YES|Yes|"") return 0 ;;\n            n|N|no|NO|No) return 1 ;;\n            *) echo "Please answer y or n." ;;\n        esac\n    done\n}\n\nshould_move_successful_input() {\n    local prompt="$1"\n    case "${MOVE_MODE}" in\n        move) return 0 ;;\n        keep) return 1 ;;\n        ask) ask_yes_no "${prompt}" ;;\n        *)\n            echo "ERROR: Invalid internal MOVE_MODE: ${MOVE_MODE}" >&2\n            return 1\n            ;;\n    esac\n}\n\nrelative_to_project() {\n    local path="$1"\n    if [[ "${path}" == "${PROJECT_ROOT}/"* ]]; then\n        printf \'%s\' "${path#${PROJECT_ROOT}/}"\n    else\n        printf \'%s\' "${path}"\n    fi\n}\n\narchive_kind() {\n    local lower_name="${1,,}"\n    case "${lower_name}" in\n        *.zip) printf \'%s\' "zip" ;;\n        *.tar.gz|*.tgz) printf \'%s\' "tar.gz" ;;\n        *) printf \'%s\' "" ;;\n    esac\n}\n\nallocate_patched_target() {\n    local source_file="$1"\n    local base target stem ext timestamp counter\n\n    base="$(basename -- "${source_file}")"\n    target="${PATCHED_DIR}/${base}"\n    if [ ! -e "${target}" ]; then\n        printf \'%s\' "${target}"\n        return 0\n    fi\n\n    case "${base,,}" in\n        *.tar.gz)\n            stem="${base:0:${#base}-7}"\n            ext="${base: -7}"\n            ;;\n        *.tgz)\n            stem="${base:0:${#base}-4}"\n            ext="${base: -4}"\n            ;;\n        *.*)\n            stem="${base%.*}"\n            ext=".${base##*.}"\n            ;;\n        *)\n            stem="${base}"\n            ext=""\n            ;;\n    esac\n\n    timestamp="$(date +%Y%m%d_%H%M%S)"\n    target="${PATCHED_DIR}/${stem}.${timestamp}${ext}"\n    counter=2\n    while [ -e "${target}" ]; do\n        target="${PATCHED_DIR}/${stem}.${timestamp}.${counter}${ext}"\n        counter=$((counter + 1))\n    done\n    printf \'%s\' "${target}"\n}\n\nmove_original_to_patched() {\n    local source_file="$1"\n    local source_rel target target_rel\n\n    source_rel="$(relative_to_project "${source_file}")"\n    target="$(allocate_patched_target "${source_file}")"\n    target_rel="$(relative_to_project "${target}")"\n\n    if ! mv -- "${source_file}" "${target}"; then\n        echo "ERROR: Could not move ${source_rel} to ${target_rel}" >&2\n        return 1\n    fi\n    echo "Moved: ${source_rel} -> ${target_rel}"\n}\n\nextract_archive_safely() {\n    local archive_file="$1"\n    local destination="$2"\n\n    "${PYTHON_BIN}" - "${archive_file}" "${destination}" <<\'PY\'\nfrom __future__ import annotations\n\nfrom pathlib import Path\nimport inspect\nimport os\nimport stat\nimport sys\nimport tarfile\nimport zipfile\n\n\ndef _clean_excepthook(exc_type, exc, traceback):\n    print(f"ERROR: {exc}", file=sys.stderr)\n\n\nsys.excepthook = _clean_excepthook\n\narchive = Path(sys.argv[1]).resolve()\ndestination = Path(sys.argv[2]).resolve()\ndestination.mkdir(parents=True, exist_ok=True)\n\nMAX_MEMBERS = 10000\nMAX_TOTAL_SIZE = 1024 * 1024 * 1024  # 1 GiB after extraction\n\n\ndef safe_target(member_name: str) -> Path:\n    # ZIP and TAR member names use POSIX-style separators. Backslashes remain\n    # ordinary filename characters on Linux and cannot escape destination.\n    target = (destination / member_name).resolve()\n    try:\n        common = os.path.commonpath((str(destination), str(target)))\n    except ValueError as exc:\n        raise RuntimeError(f"invalid archive path: {member_name!r}") from exc\n    if common != str(destination):\n        raise RuntimeError(f"unsafe path traversal in archive: {member_name!r}")\n    return target\n\n\ndef check_limits(count: int, total_size: int) -> None:\n    if count > MAX_MEMBERS:\n        raise RuntimeError(f"archive contains too many members ({count} > {MAX_MEMBERS})")\n    if total_size > MAX_TOTAL_SIZE:\n        raise RuntimeError(\n            f"archive expands beyond safety limit ({total_size} > {MAX_TOTAL_SIZE} bytes)"\n        )\n\n\nlower = archive.name.lower()\nif lower.endswith(".zip"):\n    with zipfile.ZipFile(archive, "r") as zf:\n        members = zf.infolist()\n        check_limits(len(members), sum(info.file_size for info in members))\n        for info in members:\n            safe_target(info.filename)\n            unix_mode = (info.external_attr >> 16) & 0xFFFF\n            if unix_mode and stat.S_ISLNK(unix_mode):\n                raise RuntimeError(f"symbolic links are not allowed: {info.filename!r}")\n        for info in members:\n            zf.extract(info, destination)\nelif lower.endswith((".tar.gz", ".tgz")):\n    with tarfile.open(archive, "r:gz") as tf:\n        members = tf.getmembers()\n        check_limits(len(members), sum(member.size for member in members if member.isfile()))\n        for member in members:\n            safe_target(member.name)\n            if member.issym() or member.islnk():\n                raise RuntimeError(f"links are not allowed: {member.name!r}")\n            if not (member.isdir() or member.isfile()):\n                raise RuntimeError(f"special archive member is not allowed: {member.name!r}")\n        extract_kwargs = {}\n        if "filter" in inspect.signature(tf.extract).parameters:\n            extract_kwargs["filter"] = "data"\n        for member in members:\n            tf.extract(member, destination, **extract_kwargs)\nelse:\n    raise RuntimeError(f"unsupported archive type: {archive.name}")\nPY\n}\n\nrun_python_file() {\n    local patch_file="$1"\n    local display_name="$2"\n    local extra_pythonpath="${3:-}"\n    local effective_pythonpath exit_code\n\n    echo\n    echo "============================================================"\n    echo "Running: ${display_name}"\n    echo "Working directory: ${PROJECT_ROOT}"\n    echo "Python: ${PYTHON_BIN}"\n    echo "Patch helper: $(relative_to_project "${PATCH_HELPER}")"\n    echo "============================================================"\n\n    if [ ! -f "${PATCH_HELPER}" ]; then\n        echo "NOTE: $(relative_to_project "${PATCH_HELPER}") not found."\n        echo "      Patch can still run if it embeds its own helper code."\n    fi\n\n    # Project tools must be first. A patch package may contain an old\n    # python_patch_utils.py for historical reasons; it must never override the\n    # canonical helper installed in <project>/tools/.\n    effective_pythonpath="${TOOLS_DIR}"\n    if [ -n "${extra_pythonpath}" ]; then\n        effective_pythonpath="${effective_pythonpath}:${extra_pythonpath}"\n    fi\n\n    (\n        cd "${PROJECT_ROOT}" || exit 1\n        # Running `python patch.py` puts the archive directory at sys.path[0].\n        # Execute through runpy so project tools/python_patch_utils.py remains\n        # authoritative, while package sibling modules stay importable.\n        export PYTHON_PATCH_PROJECT_TOOLS="${TOOLS_DIR}"\n        export PYTHONPATH="${effective_pythonpath}${PYTHONPATH:+:${PYTHONPATH}}"\n        "${PYTHON_BIN}" - "${patch_file}" "${PATCH_CLI_ARGS[@]}" <<\'PY_PATCH_RUNNER\'\nimport os\nfrom pathlib import Path\nimport runpy\nimport sys\n\npatch_file = str(Path(sys.argv[1]).resolve())\npatch_args = sys.argv[2:]\ntools_dir = str(Path(os.environ["PYTHON_PATCH_PROJECT_TOOLS"]).resolve())\n\n\ndef normalized(path_entry):\n    if path_entry == "":\n        return str(Path.cwd().resolve())\n    try:\n        return str(Path(path_entry).resolve())\n    except Exception:\n        return path_entry\n\n\nsys.path = [tools_dir] + [\n    entry for entry in sys.path if normalized(entry) != tools_dir\n]\nsys.argv = [patch_file, *patch_args]\nrunpy.run_path(patch_file, run_name="__main__")\nPY_PATCH_RUNNER\n    )\n    exit_code=$?\n\n    echo\n    if [ "${exit_code}" -eq 0 ]; then\n        echo "DONE: ${display_name}"\n    else\n        echo "FAILED: ${display_name} exited with code ${exit_code}"\n    fi\n\n    return "${exit_code}"\n}\n\nrun_standalone_patch() {\n    local patch_file="$1"\n    local rel_file exit_code\n\n    rel_file="$(relative_to_project "${patch_file}")"\n    run_python_file "${patch_file}" "${rel_file}"\n    exit_code=$?\n\n    if [ "${exit_code}" -ne 0 ]; then\n        echo "Kept failed patch: ${rel_file}"\n        return "${exit_code}"\n    fi\n\n    if should_move_successful_input "Move this executed patch to patchs/patched: ${rel_file}?"; then\n        if ! move_original_to_patched "${patch_file}"; then\n            exit_code=1\n        fi\n    else\n        echo "Kept: ${rel_file}"\n    fi\n\n    return "${exit_code}"\n}\n\ncollect_archive_patch_files() {\n    local extracted_dir="$1"\n    local -n output_array="$2"\n\n    mapfile -d \'\' -t output_array < <(\n        find "${extracted_dir}" -type f -iname "patch_*.py" -print0 | sort -z\n    )\n\n    if [ "${#output_array[@]}" -eq 0 ]; then\n        mapfile -d \'\' -t output_array < <(\n            find "${extracted_dir}" -type f -iname "*.py" -print0 | sort -z\n        )\n    fi\n}\n\nrun_archive_patch() {\n    local archive_file="$1"\n    local archive_rel archive_type archive_base\n    local extract_dir final_exit code internal_rel display_name\n    local -a internal_patch_files=()\n    local index\n\n    archive_rel="$(relative_to_project "${archive_file}")"\n    archive_type="$(archive_kind "${archive_file}")"\n    archive_base="$(basename -- "${archive_file}")"\n    final_exit=0\n\n    CURRENT_TEMP_DIR="$(mktemp -d "${TEMP_ROOT}/archive.XXXXXX")"\n    extract_dir="${CURRENT_TEMP_DIR}/content"\n    mkdir -p -- "${extract_dir}"\n\n    echo\n    echo "============================================================"\n    echo "Extracting patch package: ${archive_rel}"\n    echo "Archive type: ${archive_type}"\n    echo "Temporary directory: $(relative_to_project "${extract_dir}")"\n    echo "============================================================"\n\n    if ! extract_archive_safely "${archive_file}" "${extract_dir}"; then\n        code=$?\n        # The command is under !, so $? is the inverted status. Preserve a\n        # stable non-zero result for the package.\n        final_exit=1\n        echo "FAILED: Could not safely extract ${archive_rel}"\n    else\n        collect_archive_patch_files "${extract_dir}" internal_patch_files\n\n        if [ "${#internal_patch_files[@]}" -eq 0 ]; then\n            echo "FAILED: No Python patch files found inside ${archive_rel}"\n            final_exit=1\n        else\n            echo "Patch scripts inside package:"\n            for index in "${!internal_patch_files[@]}"; do\n                internal_rel="${internal_patch_files[$index]#${extract_dir}/}"\n                printf "  %2d) %s\\n" "$((index + 1))" "${internal_rel}"\n            done\n\n            for index in "${!internal_patch_files[@]}"; do\n                internal_rel="${internal_patch_files[$index]#${extract_dir}/}"\n                display_name="${archive_rel}::${internal_rel}"\n\n                run_python_file "${internal_patch_files[$index]}" "${display_name}" "${extract_dir}"\n                code=$?\n                if [ "${code}" -ne 0 ]; then\n                    final_exit="${code}"\n                    echo "Stopping package after failed patch: ${internal_rel}"\n                    break\n                fi\n            done\n        fi\n    fi\n\n    cleanup_current_temp\n    echo "Removed extracted temporary files for: ${archive_rel}"\n\n    if [ "${final_exit}" -ne 0 ]; then\n        echo "Kept failed patch package: ${archive_rel}"\n        return "${final_exit}"\n    fi\n\n    if should_move_successful_input "Move this processed patch package to patchs/patched: ${archive_rel}?"; then\n        if ! move_original_to_patched "${archive_file}"; then\n            final_exit=1\n        fi\n    else\n        echo "Kept: ${archive_rel}"\n    fi\n\n    return "${final_exit}"\n}\n\nrun_one_item() {\n    local item="$1"\n    local kind\n\n    kind="$(archive_kind "${item}")"\n    if [ -n "${kind}" ]; then\n        run_archive_patch "${item}"\n    else\n        run_standalone_patch "${item}"\n    fi\n}\n\nprint_patch_list() {\n    echo "Available patch files/packages:"\n    for i in "${!PATCH_ITEMS[@]}"; do\n        local item kind\n        item="${PATCH_ITEMS[$i]}"\n        kind="$(archive_kind "${item}")"\n        if [ -n "${kind}" ]; then\n            printf "  %2d) %s  [%s]\\n" "$((i + 1))" "$(relative_to_project "${item}")" "${kind}"\n        else\n            printf "  %2d) %s  [python]\\n" "$((i + 1))" "$(relative_to_project "${item}")"\n        fi\n    done\n}\n\nresolve_patch_selector() {\n    local selector="$1"\n    local -n output_item="$2"\n    local candidate rel base index matches=0\n\n    if [[ "${selector}" =~ ^[0-9]+$ ]]; then\n        index=$((selector - 1))\n        if [ "${index}" -lt 0 ] || [ "${index}" -ge "${#PATCH_ITEMS[@]}" ]; then\n            echo "ERROR: Patch number out of range: ${selector}" >&2\n            return 1\n        fi\n        output_item="${PATCH_ITEMS[$index]}"\n        return 0\n    fi\n\n    for candidate in "${PATCH_ITEMS[@]}"; do\n        rel="$(relative_to_project "${candidate}")"\n        base="$(basename -- "${candidate}")"\n        if [ "${selector}" = "${candidate}" ] || [ "${selector}" = "${rel}" ] || [ "${selector}" = "${base}" ]; then\n            output_item="${candidate}"\n            matches=$((matches + 1))\n        fi\n    done\n\n    if [ "${matches}" -eq 1 ]; then\n        return 0\n    fi\n    if [ "${matches}" -gt 1 ]; then\n        echo "ERROR: Patch selector is ambiguous: ${selector}" >&2\n    else\n        echo "ERROR: Patch not found: ${selector}" >&2\n    fi\n    return 1\n}\n\nrun_all_items() {\n    local item code\n    for item in "${PATCH_ITEMS[@]}"; do\n        if [ ! -f "${item}" ]; then\n            continue\n        fi\n        run_one_item "${item}"\n        code=$?\n        if [ "${code}" -ne 0 ]; then\n            echo "Stopping after failed patch file/package."\n            return "${code}"\n        fi\n    done\n    return 0\n}\n\necho "Python patch runner mini-AI v4 (${TOOL_VERSION})"\necho "Project root : ${PROJECT_ROOT}"\necho "Patch folder : ${PATCH_DIR}"\necho "Patched files: ${PATCHED_DIR}"\necho "Tools folder : ${TOOLS_DIR}"\nif [ -f "${PATCH_HELPER}" ]; then\n    echo "Patch helper : ${PATCH_HELPER}"\nelse\n    echo "Patch helper : not found"\nfi\necho\n\ncase "${RUN_MODE}" in\n    list)\n        print_patch_list\n        exit 0\n        ;;\n    all)\n        print_patch_list\n        echo\n        run_all_items\n        exit $?\n        ;;\n    one)\n        selected_item=""\n        if ! resolve_patch_selector "${PATCH_SELECTOR}" selected_item; then\n            print_patch_list\n            exit 1\n        fi\n        run_one_item "${selected_item}"\n        exit $?\n        ;;\n    interactive)\n        print_patch_list\n        echo "   a) Run all"\n        echo "   q) Quit"\n        echo\n        read -r -p "Choose a patch number, \'a\' for all, or \'q\' to quit: [a] " choice\n        case "${choice}" in\n            q|Q)\n                echo "Cancelled."\n                exit 0\n                ;;\n            \'\'|a|A|all|ALL|All)\n                run_all_items\n                exit $?\n                ;;\n            *)\n                selected_item=""\n                if ! resolve_patch_selector "${choice}" selected_item; then\n                    exit 1\n                fi\n                run_one_item "${selected_item}"\n                exit $?\n                ;;\n        esac\n        ;;\n    *)\n        echo "ERROR: Invalid internal RUN_MODE: ${RUN_MODE}" >&2\n        exit 2\n        ;;\nesac\n'
PYTHON_PATCH_TEMPLATE = '#!/usr/bin/env python3\n"""Template for compact adaptive Python patches (mini-AI v4).\n\nCopy this file to patchs/patch_<name>.py, set PATCH_NAME, then fill OPS.\nKeep shared helpers in tools/python_patch_utils.py, not in patchs/.\n"""\n\nfrom pathlib import Path\nimport sys\n\nPATCH_NAME = "example_patch"\n\nPROJECT_ROOT = Path.cwd().resolve()\nTOOLS_DIR = PROJECT_ROOT / "tools"\nsys.path.insert(0, str(TOOLS_DIR))\n\nfrom python_patch_utils import run_patch\n\n\nOPS = [\n    # Exact/auto replacement. mode="auto" tries exact -> variants -> whitespace -> fuzzy.\n    # {\n    #     "id": "change-example-block",\n    #     "kind": "replace",\n    #     "file": "relative/path/to/file.c",\n    #     "anchor": "unique nearby function/comment",\n    #     "old": """old block""",\n    #     "new": """new block""",\n    #     "mode": "auto",\n    #     "on_error": "stop",  # stop | skip | ignore\n    # },\n\n    # If/then/else example:\n    # {\n    #     "id": "local-shape-dependent-change",\n    #     "kind": "if",\n    #     "condition": {\n    #         "file": "relative/path/to/file.c",\n    #         "contains": "local code shape A",\n    #     },\n    #     "then": [\n    #         {"kind": "replace", "file": "relative/path/to/file.c", "old": "A", "new": "A\'"},\n    #     ],\n    #     "else": [\n    #         {"kind": "replace", "file": "relative/path/to/file.c", "old": "B", "new": "B\'", "on_error": "skip"},\n    #     ],\n    # },\n]\n\n\nif __name__ == "__main__":\n    raise SystemExit(run_patch(PATCH_NAME, OPS))\n'
PYTHON_PATCH_PROMPT = '# Tiêu chuẩn Python patch mini-AI v4 cho project\n\nTài liệu này dùng khi yêu cầu ChatGPT tạo patch sửa code ở local. Mục tiêu là giảm token patch, tăng khả năng thích ứng khi code local lệch nhẹ, vẫn an toàn vì có backup, thống kê lỗi, và có thể zip các file lỗi để gửi lại ChatGPT.\n\n## Cách chạy\n\n```bash\nmkdir -p patchs\ncp patch_<ten_thay_doi>.py patchs/\n# Hoặc chép gói patch .zip / .tar.gz vào patchs/\n./tools/run_python_patches.sh\n\n# Chạy không tương tác toàn bộ patch và tự chuyển patch thành công:\n./tools/run_python_patches.sh --all --move\n\n# Chạy trực tiếp patch số 2, giữ file patch gốc:\n./tools/run_python_patches.sh --patch 2 --keep\n\n# Xem toàn bộ tham số:\n./tools/run_python_patches.sh --help\n```\n\nQuy ước:\n\n- `tools/python_patch_utils.py` là helper dùng chung, không đặt trong `patchs/`.\n- Runner nhận patch độc lập `.py` và gói `.zip`, `.tar.gz`, `.tgz`.\n- Với gói nén, runner giải nén an toàn vào thư mục tạm và chạy đệ quy các file `patch_*.py` theo thứ tự tên; nếu không có file theo mẫu đó thì chạy toàn bộ `.py`.\n- Sau khi chạy, runner xóa nội dung giải nén tạm. Chỉ file `.py` độc lập hoặc file nén gốc được chuyển vào `patchs/patched/`.\n- Nếu tên đích đã tồn tại, runner tạo tên có timestamp thay vì ghi đè.\n- Runner hỗ trợ `-h`/`--help`, `-a`/`--all`, `-p`/`--patch`, `-y`/`--yes`, `--move`, `--keep`, `--list` và các tùy chọn ZIP lỗi.\n- Khi một patch hoặc package trả về lỗi, runner dừng ngay; không hỏi có tiếp tục patch sau hay không.\n- Patch không tự build/flash/monitor/đọc log/phần cứng.\n- Patch chỉ sửa đúng file nằm trong yêu cầu.\n\n\n## Gói patch nén\n\nGói nén hữu ích khi một thay đổi cần nhiều patch Python hoặc kèm dữ liệu phụ. Cấu trúc có thể có nhiều cấp thư mục:\n\n```text\npatch_feature_bundle.zip\n├── phase_01/patch_feature_phase_01.py\n├── phase_02/patch_feature_phase_02.py\n└── resources/config.json\n```\n\nQuy tắc runner v4:\n\n1. Không giải nén trực tiếp vào `patchs/` hay project root.\n2. Chặn đường dẫn thoát thư mục (`../`), symlink, hardlink và special file.\n3. Chạy các patch Python theo thứ tự đường dẫn đã sắp xếp.\n4. Xóa toàn bộ nội dung giải nén sau khi hoàn tất hoặc lỗi.\n5. Khi người dùng đồng ý dọn dẹp, chỉ chuyển file nén gốc vào `patchs/patched/`; các `.py` đã giải nén không được giữ riêng.\n\n## Skeleton patch ngắn nên dùng\n\n```python\n#!/usr/bin/env python3\nfrom pathlib import Path\nimport sys\n\nPATCH_NAME = "ten_patch_ngan_gon"\nPROJECT_ROOT = Path.cwd().resolve()\nsys.path.insert(0, str(PROJECT_ROOT / "tools"))\n\nfrom python_patch_utils import run_patch\n\nOPS = [\n    {\n        "id": "mo-ta-ngan",\n        "kind": "replace",\n        "file": "relative/path/to/file.c",\n        "anchor": "ten_ham_hoac_comment_gan_do",\n        "old": """old block""",\n        "new": """new block""",\n        "mode": "auto",\n        "on_error": "stop",\n    },\n]\n\nif __name__ == "__main__":\n    raise SystemExit(run_patch(PATCH_NAME, OPS))\n```\n\n## Operation kinds\n\n### 1. `replace`\n\nThay một block. Mặc định `mode="auto"` sẽ thử theo thứ tự:\n\n1. exact match;\n2. old variants nếu có;\n3. whitespace-normalized match;\n4. fuzzy line-window match.\n\nVí dụ ngắn:\n\n```python\n{\n    "id": "bump-hook-marker",\n    "kind": "replace",\n    "file": "battle/hook.nim",\n    "anchor": "hook status",\n    "old": "[MWF] hook status V7 where=",\n    "new": "[MWF] hook status V8 where=",\n}\n```\n\nCác field hữu ích:\n\n- `old_variants`: list các block cũ có thể gặp.\n- `already`: chuỗi hoặc list chuỗi dùng để nhận biết đã patch rồi.\n- `mode`: `auto`, `exact`, `normalized_ws`, `fuzzy`, `regex`.\n- `fuzzy_min`: mặc định `0.88`, tăng lên nếu muốn chặt hơn.\n- `anchor_radius`: chỉ tìm quanh anchor để giảm mơ hồ.\n- `on_error`: `stop`, `skip`, `ignore`.\n\n### 2. `replace_any`\n\nDùng khi local có thể đang ở nhiều dạng A/B/C và mỗi dạng cần new khác nhau.\n\n```python\n{\n    "id": "support-two-local-shapes",\n    "kind": "replace_any",\n    "file": "src/main.c",\n    "anchor": "target_function",\n    "replacements": [\n        {"old": "old shape A", "new": "new shape A"},\n        {"old": "old shape B", "new": "new shape B"},\n    ],\n}\n```\n\n### 3. `insert_after` / `insert_before`\n\nChèn quanh anchor duy nhất. Có idempotent check bằng nội dung `insert` hoặc field `already`.\n\n```python\n{\n    "id": "add-helper-call",\n    "kind": "insert_after",\n    "file": "src/main.c",\n    "anchor": "init_system();\\n",\n    "insert": "    init_new_feature();\\n",\n}\n```\n\n### 4. `regex_replace`\n\nDùng regex khi exact block quá dài hoặc có giá trị biến đổi nhẹ.\n\n```python\n{\n    "id": "bump-version",\n    "kind": "regex_replace",\n    "file": "src/version.h",\n    "pattern": r\'#define APP_VERSION "[^"]+"\',\n    "repl": \'#define APP_VERSION "0.1.26"\',\n    "count": 1,\n}\n```\n\n`count` mặc định là `1`. Nếu regex match 0 hoặc nhiều hơn count thì patch báo lỗi, không tự đoán. Có thể dùng `count="any"` khi thật sự muốn thay toàn bộ.\n\n### 5. `if`\n\nDùng cho logic nếu-thì-không-thì.\n\n```python\n{\n    "id": "shape-dependent-patch",\n    "kind": "if",\n    "condition": {\n        "file": "src/main.c",\n        "contains": "old local shape A",\n    },\n    "then": [\n        {"kind": "replace", "file": "src/main.c", "old": "A", "new": "A\'"},\n    ],\n    "else": [\n        {"kind": "replace", "file": "src/main.c", "old": "B", "new": "B\'", "on_error": "skip"},\n    ],\n}\n```\n\nCondition hỗ trợ:\n\n- `contains`\n- `not_contains`\n- `regex`\n- `not_regex`\n- `exists`\n- `path_exists`\n\n### 6. `first_success`\n\nThử nhiều alternative, chọn cái đầu tiên match thành công. Chỉ nên dùng cho các alternative nhỏ và độc lập.\n\n```python\n{\n    "id": "try-known-layouts",\n    "kind": "first_success",\n    "alternatives": [\n        [{"kind": "replace", "file": "src/a.c", "old": "layout A", "new": "new A"}],\n        [{"kind": "replace", "file": "src/a.c", "old": "layout B", "new": "new B"}],\n    ],\n}\n```\n\n### 7. `write`, `append`, `prepend`\n\n- `write`: tạo mới hoặc ghi đè file nếu khác nội dung, có backup nếu file đã tồn tại.\n- `append` / `prepend`: thêm nội dung vào cuối/đầu file, có check idempotent.\n\n## Chính sách lỗi\n\nMỗi operation có thể đặt:\n\n```python\n"on_error": "stop"   # mặc định, dừng toàn patch\n"on_error": "skip"   # ghi nhận lỗi, bỏ qua operation đó, chạy tiếp operation khác\n"on_error": "ignore" # bỏ qua thật sự, không tính failed; chỉ dùng cho optional cleanup nhỏ\n```\n\nKhuyến nghị:\n\n- Các patch phụ thuộc nhau: để `stop`.\n- Các patch độc lập theo file/tính năng phụ: dùng `skip`.\n- Không dùng `ignore` cho thay đổi code chính.\n\nKhi patch chạy thành công nhưng `patched = 0` và `created = 0`, helper không in bảng `Patch summary`; thay vào đó hiển thị thông báo nổi bật `PATCH KHÔNG THAY ĐỔI CODE`, có dòng trống trước và sau. Nếu có `failed`, bảng summary lỗi vẫn được in đầy đủ và runner dừng ngay.\n\nKhi có lỗi, helper sẽ in:\n\n- `ERROR`\n- `File`\n- `Op`\n- `Mode`\n- `Anchor`\n- preview block cần tìm\n- nearby context/candidate context nếu có\n- summary cuối cùng và danh sách failed files\n\nNếu chạy trong terminal tương tác, khi có lỗi helper sẽ hỏi có zip các file lỗi không. Có thể bỏ xác nhận bằng CLI:\n\n```bash\npython3 patchs/patch_example.py --zip-failed --keep-failed-zip\npython3 patchs/patch_example.py --no-zip-failed\npython3 patchs/patch_example.py --help\n```\n\nZIP được lưu tại:\n\n```text\npatchs/failed_patch_files/<patch_name>_failed_<timestamp>.zip\n```\n\nZip giữ nguyên đường dẫn tương đối để gửi lại ChatGPT.\n\n## Prompt chuẩn đưa cho ChatGPT\n\n```text\nHãy cung cấp file Python patch, không cung cấp prompt sửa code.\n\nDùng helper tools/python_patch_utils.py phiên bản mini-AI v4 nếu có. Patch nên dùng dạng khai báo run_patch(PATCH_NAME, OPS) để giảm token.\n\nYêu cầu bắt buộc:\n1. File patch đặt tên duy nhất dạng patch_<ten_ngan_gon>.py; nếu đóng gói nhiều file thì dùng tên duy nhất dạng patch_<ten_ngan_gon>.zip hoặc .tar.gz.\n2. Patch chạy từ project root bằng ./tools/run_python_patches.sh.\n3. Không thay đổi runner, không build/flash/monitor/đọc log/phần cứng trong patch.\n4. Chỉ sửa file liên quan trực tiếp yêu cầu.\n5. Ưu tiên operation kind: replace, replace_any, regex_replace, insert_after, insert_before, if, first_success, write.\n6. Mỗi operation phải có id ngắn, file, anchor nếu có thể.\n7. Với block dễ lệch nhẹ ở local, dùng mode="auto" hoặc old_variants; chỉ dùng fuzzy khi block đủ dài và anchor đủ rõ.\n8. Nếu operation phụ thuộc operation trước, để on_error="stop". Nếu độc lập, có thể đặt on_error="skip".\n9. Nếu cần nếu-thì, dùng kind="if" hoặc replace_any thay vì viết logic Python dài.\n10. Nếu lỗi, helper phải tự báo file lỗi; hỗ trợ `--zip-failed`, `--no-zip-failed`, `--keep-failed-zip`, `--delete-failed-zip` và `-h`/`--help`.\n11. Không dùng replace mơ hồ trên chuỗi ngắn xuất hiện nhiều nơi; dùng anchor_radius, regex count=1, hoặc exact block lớn hơn.\n```\n\n## Ghi chú an toàn\n\n- `mode="auto"` không có nghĩa là đoán bừa. Nếu tìm thấy nhiều candidate, helper báo ambiguous.\n- Fuzzy matching chỉ nên dùng khi `anchor` đủ đặc trưng hoặc block đủ dài.\n- Backup được tạo trước lần ghi đầu tiên vào mỗi file.\n- Nếu một patch chạy nhiều lần, backup cũ không bị ghi đè; helper tự thêm hậu tố `.2`, `.3`, ... khi cần.\n'


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Install or upgrade the complete Python Patch Tool v4 library."
    )
    parser.add_argument(
        "--project-root",
        type=Path,
        default=Path.cwd(),
        help="Target project root (default: current directory).",
    )
    return parser.parse_args()


def safe_backup_name(rel_path: str) -> str:
    rel = Path(rel_path)
    timestamp = dt.datetime.now().strftime("%Y%m%d_%H%M%S_%f")
    return f"{rel.name}.{INSTALLER_NAME}.{timestamp}.install.bak"


def backup_file(root: Path, rel_path: str) -> Path:
    source = root / rel_path
    destination = root / "patchs" / "backup" / rel_path / safe_backup_name(rel_path)
    destination.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(source, destination)
    return destination


def ensure_executable(path: Path) -> bool:
    old_mode = path.stat().st_mode
    new_mode = old_mode | 0o111
    if new_mode == old_mode:
        return False
    path.chmod(new_mode)
    print(f"chmod  : {path}")
    return True


def write_if_changed(
    root: Path,
    rel_path: str,
    content: str,
    *,
    executable: bool = False,
) -> str:
    path = root / rel_path
    if path.exists():
        old = path.read_text(encoding="utf-8")
        if old == content:
            print(f"unchanged/check: {rel_path}")
            if executable:
                ensure_executable(path)
            return "unchanged"
        backup = backup_file(root, rel_path)
        path.write_text(content, encoding="utf-8")
        print(f"backup : {backup.relative_to(root)}")
        print(f"patched: {rel_path}")
        result = "patched"
    else:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
        print(f"created: {rel_path}")
        result = "created"

    if executable:
        ensure_executable(path)
    return result


def choose_existing(root: Path, candidates: list[str], default_rel: str) -> str:
    for rel_path in candidates:
        if (root / rel_path).exists():
            return rel_path
    return default_rel


def main() -> int:
    args = parse_args()
    root = args.project_root.expanduser().resolve()
    root.mkdir(parents=True, exist_ok=True)
    (root / "tools").mkdir(parents=True, exist_ok=True)
    (root / "patchs" / "patched").mkdir(parents=True, exist_ok=True)

    template_rel = choose_existing(
        root,
        [
            "tools/PYTHON_PATCH_TEMPLATE.py",
            "PYTHON_PATCH_TEMPLATE.py",
            "document/PYTHON_PATCH_TEMPLATE.py",
            "docs/PYTHON_PATCH_TEMPLATE.py",
        ],
        "tools/PYTHON_PATCH_TEMPLATE.py",
    )
    prompt_default = (
        "document/PYTHON_PATCH_STANDARD_PROMPT.md"
        if (root / "document").is_dir()
        else "tools/PYTHON_PATCH_STANDARD_PROMPT.md"
    )
    prompt_rel = choose_existing(
        root,
        [
            "PYTHON_PATCH_STANDARD_PROMPT.md",
            "document/PYTHON_PATCH_STANDARD_PROMPT.md",
            "docs/PYTHON_PATCH_STANDARD_PROMPT.md",
            "tools/PYTHON_PATCH_STANDARD_PROMPT.md",
        ],
        prompt_default,
    )

    targets = [
        ("tools/python_patch_utils.py", PYTHON_PATCH_UTILS, True),
        ("tools/run_python_patches.sh", RUN_PYTHON_PATCHES, True),
        (template_rel, PYTHON_PATCH_TEMPLATE, True),
        (prompt_rel, PYTHON_PATCH_PROMPT, False),
    ]
    stats = {"patched": 0, "created": 0, "unchanged": 0}
    for rel_path, content, executable in targets:
        result = write_if_changed(root, rel_path, content, executable=executable)
        stats[result] += 1

    if stats["patched"] == 0 and stats["created"] == 0:
        print()
        print("\033[93m\033[1m============================================================\033[0m")
        print("\033[93m\033[1mPYTHON PATCH TOOL V4 KHÔNG CÓ THAY ĐỔI\033[0m")
        print("\033[93m\033[1m============================================================\033[0m")
        print()
    else:
        print("Install summary:")
        print(f"  patched : {stats['patched']}")
        print(f"  created : {stats['created']}")
        print(f"  unchanged/check: {stats['unchanged']}")

    print(f"Python Patch Tool v4 ({TOOL_VERSION}) installed successfully.")
    return 0


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except Exception as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        raise SystemExit(1)
